(function () {
  function LightningEffect(canvas, options = {}) {
    const ctx = canvas.getContext('2d');
    let width, height, centerX, centerY;
    let animationId = null;
    let time = 0;

    const config = {
      mainColor: "#FFFFFF",
      coreColor: "#A8E4FF",
      branchColor: "#0A74FF",
      glowColor: "#4FC3FF",
      lineWidth: 3,
      branchWidth: 2,
      // speed: controla tudo proporcionalmente
      // 0.5 = lento, 1 = normal, 2 = rápido, 3 = frenético
      speed: 1,
      ...options
    };

    // atalho interno
    const S = () => config.speed;

    const COLORS = [config.mainColor, config.coreColor, config.branchColor, config.glowColor, '#7dd6ff'];

    // --- listas vivas ---
    const bolts = [];
    const particles = [];
    const explosions = [];

    // timers de spawn
    let cornerTimer = 0;
    let edgeTimer = 0;
    let explosionTimer = 0;
    let ambientTimer = 0;

    // ---------- helpers ----------
    function rand(a, b) { return a + Math.random() * (b - a); }
    function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }

    function resize() {
      width = canvas.clientWidth;
      height = canvas.clientHeight;
      canvas.width = width;
      canvas.height = height;
      centerX = width / 2;
      centerY = height / 2;
    }

    // gera pontos zig-zag perpendiculares ao segmento
    function zigzag(x1, y1, x2, y2, segs, noise) {
      const pts = [];
      const dx = x2 - x1, dy = y2 - y1;
      const len = Math.sqrt(dx * dx + dy * dy) || 1;
      const px = -dy / len, py = dx / len;
      for (let i = 0; i <= segs; i++) {
        const t = i / segs;
        const bx = x1 + dx * t, by = y1 + dy * t;
        const env = Math.sin(t * Math.PI) * noise * (1 + Math.random() * 0.5);
        pts.push({ x: bx + px * env * (Math.random() - 0.5) * 2, y: by + py * env * (Math.random() - 0.5) * 2 });
      }
      return pts;
    }

    function strokePts(pts, col, lw, blur) {
      if (pts.length < 2) return;
      ctx.beginPath();
      ctx.moveTo(pts[0].x, pts[0].y);
      for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
      ctx.shadowBlur = blur;
      ctx.shadowColor = col;
      ctx.strokeStyle = col;
      ctx.lineWidth = lw;
      ctx.lineCap = 'round';
      ctx.stroke();
    }

    // ---------- Bolt ----------
    class Bolt {
      constructor(x1, y1, x2, y2, opts = {}) {
        this.x1 = x1; this.y1 = y1;
        this.x2 = x2; this.y2 = y2;
        this.life = 1;
        this.decay = (opts.decay ?? rand(0.04, 0.12)) * S();
        this.segs = opts.segs ?? Math.floor(rand(8, 18));
        this.noise = opts.noise ?? rand(15, 45);
        this.color = opts.color ?? pick(COLORS);
        this.width = opts.width ?? rand(1, 3);
        this.flicker = Math.random() < 0.4;
        this.pts = zigzag(x1, y1, x2, y2, this.segs, this.noise);
        this.branches = this._makeBranches();
      }

      _makeBranches() {
        const br = [];
        const count = Math.floor(rand(1, 5));
        for (let i = 0; i < count; i++) {
          const idx = Math.floor(rand(2, this.pts.length - 2));
          if (!this.pts[idx]) continue;
          const p = this.pts[idx];
          const ang = Math.atan2(this.y2 - this.y1, this.x2 - this.x1) + (Math.random() - 0.5) * 2.5;
          const len = rand(20, 70);
          const bpts = zigzag(p.x, p.y, p.x + Math.cos(ang) * len, p.y + Math.sin(ang) * len, 6, this.noise * 0.4);
          br.push({ pts: bpts, w: this.width * 0.5 });
          if (Math.random() < 0.3) {
            const last = bpts[bpts.length - 1];
            const ang2 = ang + (Math.random() - 0.5) * 2;
            const l2 = rand(10, 30);
            br.push({ pts: zigzag(last.x, last.y, last.x + Math.cos(ang2) * l2, last.y + Math.sin(ang2) * l2, 4, 5), w: this.width * 0.3 });
          }
        }
        return br;
      }

      update() {
        this.life -= this.decay;
        // re-ziguezagueia levemente enquanto some
        if (this.life < 0.4 && Math.random() < 0.3) {
          this.pts = zigzag(this.x1, this.y1, this.x2, this.y2, this.segs, this.noise * this.life);
        }
      }

      draw() {
        if (this.flicker && Math.random() < 0.3) return;
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        strokePts(this.pts, this.color, this.width, 16);
        strokePts(this.pts, '#ffffff', this.width * 0.3, 0);
        for (const b of this.branches) {
          strokePts(b.pts, config.branchColor, b.w, 8);
        }
        ctx.globalAlpha = 1;
      }
    }

    // ---------- Particle (mini-raio voador) ----------
    class Particle {
      constructor(x, y) {
        const ang = Math.random() * Math.PI * 2;
        const spd = rand(1, 5) * S();
        this.x = x; this.y = y;
        this.vx = Math.cos(ang) * spd;
        this.vy = Math.sin(ang) * spd;
        this.life = 1;
        this.decay = rand(0.015, 0.04) * S();
        this.tail = rand(8, 20);
        this.w = rand(0.5, 1.5);
        this.col = pick(COLORS);
        this.dot = Math.random() < 0.35;
      }

      update() {
        this.x += this.vx; this.y += this.vy;
        this.vy += 0.03 * S();
        this.vx *= 0.99; this.vy *= 0.99;
        this.life -= this.decay;
      }

      draw() {
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        if (this.dot) {
          ctx.beginPath();
          ctx.arc(this.x, this.y, this.w * 2 * a, 0, Math.PI * 2);
          ctx.fillStyle = this.col;
          ctx.fill();
        } else {
          const tx = this.x - this.vx * this.tail, ty = this.y - this.vy * this.tail;
          const pts = zigzag(tx, ty, this.x, this.y, 5, 3 * a);
          strokePts(pts, this.col, this.w, 8);
          strokePts(pts, '#ffffff', this.w * 0.3, 0);
          // mini-galho ocasional
          if (a > 0.4 && Math.random() < 0.25 && pts.length > 2) {
            const bi = Math.floor(Math.random() * pts.length);
            const bp = pts[bi];
            const bang = Math.atan2(this.vy, this.vx) + (Math.random() - 0.5) * 2.5;
            const bl = rand(6, 14);
            const bpts = zigzag(bp.x, bp.y, bp.x + Math.cos(bang) * bl, bp.y + Math.sin(bang) * bl, 4, 3);
            strokePts(bpts, config.branchColor, 0.6, 5);
          }
        }
        ctx.globalAlpha = 1;
      }
    }

    // ---------- CenterExplosion ----------
    class CenterExplosion {
      constructor(x, y) {
        this.x = x; this.y = y;
        this.life = 1;
        this.decay = 0.014 * S();
        this.rays = [];
        const count = Math.floor(rand(8, 16));
        for (let i = 0; i < count; i++) {
          const ang = Math.random() * Math.PI * 2;
          const len = rand(40, 130);
          this.rays.push({
            pts: zigzag(x, y, x + Math.cos(ang) * len, y + Math.sin(ang) * len, 8, 15),
            w: rand(0.8, 2.5),
            col: pick(COLORS)
          });
        }
      }

      update() { this.life -= this.decay; }

      draw() {
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        // flash central
        const r = 8 + (1 - a) * 60;
        const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r);
        g.addColorStop(0, `rgba(255,255,255,${a})`);
        g.addColorStop(0.4, `rgba(79,195,255,${a * 0.6})`);
        g.addColorStop(1, 'transparent');
        ctx.fillStyle = g;
        ctx.beginPath();
        ctx.arc(this.x, this.y, r, 0, Math.PI * 2);
        ctx.fill();
        // raios
        for (const ray of this.rays) {
          strokePts(ray.pts, ray.col, ray.w, 14);
          strokePts(ray.pts, '#ffffff', ray.w * 0.3, 0);
        }
        ctx.globalAlpha = 1;
      }
    }

    // ---------- spawn helpers ----------
    function spawnCornerBolt() {
      const corners = [
        { x: 0, y: 0 }, { x: width, y: 0 },
        { x: 0, y: height }, { x: width, y: height }
      ];
      const c = pick(corners);
      const tx = centerX + rand(-80, 80);
      const ty = centerY + rand(-80, 80);
      bolts.push(new Bolt(c.x, c.y, tx, ty));
    }

    function spawnEdgeBolt() {
      const edge = Math.floor(Math.random() * 4);
      let x1, y1;
      if (edge === 0) { x1 = rand(0, width); y1 = 0; }
      else if (edge === 1) { x1 = rand(0, width); y1 = height; }
      else if (edge === 2) { x1 = 0; y1 = rand(0, height); }
      else { x1 = width; y1 = rand(0, height); }
      const ang = Math.atan2(centerY - y1, centerX - x1) + (Math.random() - 0.5) * 1.2;
      const dist = rand(80, Math.min(width, height) * 0.7);
      bolts.push(new Bolt(x1, y1, x1 + Math.cos(ang) * dist, y1 + Math.sin(ang) * dist));
    }

    function spawnAmbient() {
      const x = rand(50, width - 50), y = rand(50, height - 50);
      const ang = Math.random() * Math.PI * 2;
      const len = rand(30, 90);
      bolts.push(new Bolt(x, y, x + Math.cos(ang) * len, y + Math.sin(ang) * len, { decay: rand(0.06, 0.16) * S(), noise: rand(10, 25) }));
    }

    function spawnExplosion() {
      const ex = centerX + rand(-40, 40);
      const ey = centerY + rand(-40, 40);
      explosions.push(new CenterExplosion(ex, ey));
      for (let i = 0; i < 30; i++) particles.push(new Particle(ex, ey));
    }

    // ---------- loop principal ----------
    function animate() {
      if (!canvas.isConnected) {
        if (animationId) cancelAnimationFrame(animationId);
        return;
      }

      ctx.fillStyle = 'rgba(0,0,0,0.14)';
      ctx.fillRect(0, 0, width, height);
      ctx.shadowBlur = 0;

      time += 0.016 * S();
      cornerTimer += 0.016 * S();
      edgeTimer += 0.016 * S();
      explosionTimer += 0.016 * S();
      ambientTimer += 0.016 * S();

      if (cornerTimer > rand(0.4, 1.0) / S()) { spawnCornerBolt(); cornerTimer = 0; }
      if (edgeTimer > rand(0.15, 0.45) / S()) { spawnEdgeBolt(); if (Math.random() < 0.4) spawnEdgeBolt(); edgeTimer = 0; }
      if (explosionTimer > rand(1.5, 3.0) / S()) { spawnExplosion(); explosionTimer = 0; }
      if (ambientTimer > rand(0.1, 0.3) / S()) { spawnAmbient(); if (Math.random() < 0.3) spawnAmbient(); ambientTimer = 0; }

      // brilho suave no centro
      const gr = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, Math.min(width, height) * 0.35);
      gr.addColorStop(0, 'rgba(10,116,255,0.04)');
      gr.addColorStop(1, 'transparent');
      ctx.fillStyle = gr;
      ctx.fillRect(0, 0, width, height);

      for (let i = bolts.length - 1; i >= 0; i--) {
        bolts[i].update(); bolts[i].draw();
        if (bolts[i].life <= 0) bolts.splice(i, 1);
      }
      for (let i = explosions.length - 1; i >= 0; i--) {
        explosions[i].update(); explosions[i].draw();
        if (explosions[i].life <= 0) explosions.splice(i, 1);
      }
      for (let i = particles.length - 1; i >= 0; i--) {
        particles[i].update(); particles[i].draw();
        if (particles[i].life <= 0) particles.splice(i, 1);
      }

      ctx.shadowBlur = 0;
      animationId = requestAnimationFrame(animate);
    }

    function init() {
      resize();
      window.addEventListener('resize', resize);
      // seed inicial para não começar vazio
      for (let i = 0; i < 4; i++) spawnCornerBolt();
      for (let i = 0; i < 6; i++) spawnEdgeBolt();
      for (let i = 0; i < 10; i++) spawnAmbient();
      animate();
    }

    init();

    return {
      dispose: () => {
        if (animationId) cancelAnimationFrame(animationId);
        window.removeEventListener('resize', resize);
      },
      // altera a velocidade em tempo real (0.1 = quase parado, 1 = normal, 3 = frenético)
      setSpeed: (v) => { config.speed = Math.max(0.1, v); }
    };
  }

  window.TubesCursor = LightningEffect;
})();